import { useTranslation } from "react-i18next";
import { Clock, Users, ChefHat, Image, X, Loader2, Flame, ChevronDown, ChevronUp, FileText } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible";
import { RecipeData, DIFFICULTY_OPTIONS, RecipeDifficulty, NutritionInfo } from "./RecipeTypes";
import { useRef, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface RecipeBasicStepProps {
  data: Partial<RecipeData>;
  coverImage: string | null;
  nutrition: NutritionInfo;
  introduction: string;
  onDataChange: (data: Partial<RecipeData>) => void;
  onCoverImageChange: (url: string | null) => void;
  onNutritionChange: (nutrition: NutritionInfo) => void;
  onIntroductionChange: (introduction: string) => void;
}

const RecipeBasicStep = ({ data, coverImage, nutrition, introduction, onDataChange, onCoverImageChange, onNutritionChange, onIntroductionChange }: RecipeBasicStepProps) => {
  const { t } = useTranslation();
  const imageInputRef = useRef<HTMLInputElement>(null);
  const [showNutrition, setShowNutrition] = useState(
    !!(nutrition.calories || nutrition.protein || nutrition.carbs || nutrition.fat)
  );
  const [uploading, setUploading] = useState(false);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      toast.error(t("common.imageTooLarge", "图片不能超过5MB"));
      return;
    }

    setUploading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");

      const fileExt = file.name.split(".").pop();
      const fileName = `${user.id}/${Date.now()}-recipe-cover.${fileExt}`;

      const { error: uploadError } = await supabase.storage
        .from("community-posts")
        .upload(fileName, file);

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from("community-posts")
        .getPublicUrl(fileName);

      onCoverImageChange(publicUrl);
    } catch (error) {
      console.error("Upload error:", error);
      toast.error(t("common.uploadError", "上传失败"));
    } finally {
      setUploading(false);
      if (imageInputRef.current) {
        imageInputRef.current.value = "";
      }
    }
  };

  return (
    <div className="space-y-6">
      {/* Cover Image */}
      <div className="space-y-2">
        <Label>{t("recipe.coverImage", "封面图片")}</Label>
        <input
          ref={imageInputRef}
          type="file"
          accept="image/*"
          className="hidden"
          onChange={handleImageUpload}
        />
        {coverImage ? (
          <div className="relative aspect-video rounded-lg overflow-hidden bg-muted">
            <img src={coverImage} alt="" className="w-full h-full object-cover" />
            <button
              type="button"
              onClick={() => onCoverImageChange(null)}
              className="absolute top-2 right-2 p-1 bg-black/50 rounded-full text-white hover:bg-black/70"
            >
              <X className="h-4 w-4" />
            </button>
          </div>
        ) : (
          <button
            type="button"
            onClick={() => imageInputRef.current?.click()}
            disabled={uploading}
            className="w-full aspect-video rounded-lg border-2 border-dashed border-muted-foreground/30 flex flex-col items-center justify-center gap-2 text-muted-foreground hover:border-primary hover:text-primary transition-colors"
          >
            {uploading ? (
              <Loader2 className="h-8 w-8 animate-spin" />
            ) : (
              <>
                <Image className="h-8 w-8" />
                <span className="text-sm">{t("recipe.addCoverImage", "添加封面图片")}</span>
              </>
            )}
          </button>
        )}
      </div>

      {/* Recipe Name */}
      <div className="space-y-2">
        <Label htmlFor="recipe-name">{t("recipe.name", "食谱名称")} *</Label>
        <Input
          id="recipe-name"
          value={data.recipe_name || ""}
          onChange={(e) => onDataChange({ ...data, recipe_name: e.target.value })}
          placeholder={t("recipe.namePlaceholder", "如：红烧肉、番茄炒蛋")}
        />
      </div>

      {/* Subtitle - Food Philosophy */}
      <div className="space-y-2">
        <Label htmlFor="subtitle">
          {t("recipe.subtitle", "副标题")}
          <span className="text-xs text-muted-foreground ml-1">({t("common.optional", "可选")})</span>
        </Label>
        <Input
          id="subtitle"
          value={data.subtitle || ""}
          onChange={(e) => onDataChange({ ...data, subtitle: e.target.value })}
          placeholder={t("recipe.subtitlePlaceholder", "一句话描述这道菜的美食哲学或灵魂")}
        />
      </div>

      {/* Food Introduction */}
      <div className="space-y-2">
        <Label htmlFor="introduction">
          <FileText className="h-4 w-4 inline mr-1" />
          {t("recipe.introduction", "美食介绍")}
        </Label>
        <Textarea
          id="introduction"
          value={introduction}
          onChange={(e) => onIntroductionChange(e.target.value)}
          placeholder={t("recipe.introductionPlaceholder", "介绍这道美食的特色、口感、来源故事等...")}
          rows={Math.max(3, Math.min(12, (introduction?.split('\n').length || 1) + 1))}
          className="resize-y min-h-[80px]"
        />
        {introduction && (
          <p className="text-xs text-muted-foreground text-right">
            {introduction.length} {t("common.characters", "字")}
          </p>
        )}
      </div>

      {/* Cook Time */}
      <div className="space-y-2">
        <Label htmlFor="cook-time">
          <Clock className="h-4 w-4 inline mr-1" />
          {t("recipe.cookTime", "烹饪时间")} *
        </Label>
        <div className="flex items-center gap-2">
          <Input
            id="cook-time"
            type="number"
            min={1}
            value={data.cook_time || ""}
            onChange={(e) => onDataChange({ ...data, cook_time: parseInt(e.target.value) || 0 })}
            placeholder="30"
            className="w-24"
          />
          <span className="text-sm text-muted-foreground">{t("recipe.minutes", "分钟")}</span>
        </div>
      </div>

      {/* Difficulty */}
      <div className="space-y-2">
        <Label>
          <ChefHat className="h-4 w-4 inline mr-1" />
          {t("recipe.difficulty", "难度")} *
        </Label>
        <Select
          value={data.difficulty || ""}
          onValueChange={(value) => onDataChange({ ...data, difficulty: value as RecipeDifficulty })}
        >
          <SelectTrigger>
            <SelectValue placeholder={t("recipe.selectDifficulty", "选择难度")} />
          </SelectTrigger>
          <SelectContent>
            {DIFFICULTY_OPTIONS.map((option) => (
              <SelectItem key={option.value} value={option.value}>
                {t(option.labelKey, option.value)}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      {/* Servings */}
      <div className="space-y-2">
        <Label htmlFor="servings">
          <Users className="h-4 w-4 inline mr-1" />
          {t("recipe.servings", "份量")} *
        </Label>
        <div className="flex items-center gap-2">
          <Input
            id="servings"
            type="number"
            min={1}
            value={data.servings || ""}
            onChange={(e) => onDataChange({ ...data, servings: parseInt(e.target.value) || 0 })}
            placeholder="2"
            className="w-24"
          />
          <span className="text-sm text-muted-foreground">{t("recipe.people", "人份")}</span>
        </div>
      </div>

      {/* Optional Nutrition Info */}
      <Collapsible open={showNutrition} onOpenChange={setShowNutrition}>
        <CollapsibleTrigger asChild>
          <Button variant="ghost" type="button" className="w-full justify-between px-0 hover:bg-transparent">
            <span className="flex items-center gap-2 text-sm font-medium">
              <Flame className="h-4 w-4" />
              {t("recipe.nutritionInfo", "营养信息")}
              <span className="text-xs text-muted-foreground font-normal">
                ({t("common.optional", "可选")})
              </span>
            </span>
            {showNutrition ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
          </Button>
        </CollapsibleTrigger>
        <CollapsibleContent className="space-y-4 pt-2">
          <div className="grid grid-cols-2 gap-4">
            {/* Calories */}
            <div className="space-y-1">
              <Label htmlFor="calories" className="text-xs">
                {t("recipe.calories", "卡路里")}
              </Label>
              <div className="flex items-center gap-1">
                <Input
                  id="calories"
                  type="number"
                  min={0}
                  value={nutrition.calories || ""}
                  onChange={(e) => onNutritionChange({ ...nutrition, calories: parseInt(e.target.value) || undefined })}
                  placeholder="300"
                  className="h-8"
                />
                <span className="text-xs text-muted-foreground">kcal</span>
              </div>
            </div>

            {/* Protein */}
            <div className="space-y-1">
              <Label htmlFor="protein" className="text-xs">
                {t("recipe.protein", "蛋白质")}
              </Label>
              <div className="flex items-center gap-1">
                <Input
                  id="protein"
                  type="number"
                  min={0}
                  value={nutrition.protein || ""}
                  onChange={(e) => onNutritionChange({ ...nutrition, protein: parseInt(e.target.value) || undefined })}
                  placeholder="20"
                  className="h-8"
                />
                <span className="text-xs text-muted-foreground">g</span>
              </div>
            </div>

            {/* Carbs */}
            <div className="space-y-1">
              <Label htmlFor="carbs" className="text-xs">
                {t("recipe.carbs", "碳水")}
              </Label>
              <div className="flex items-center gap-1">
                <Input
                  id="carbs"
                  type="number"
                  min={0}
                  value={nutrition.carbs || ""}
                  onChange={(e) => onNutritionChange({ ...nutrition, carbs: parseInt(e.target.value) || undefined })}
                  placeholder="30"
                  className="h-8"
                />
                <span className="text-xs text-muted-foreground">g</span>
              </div>
            </div>

            {/* Fat */}
            <div className="space-y-1">
              <Label htmlFor="fat" className="text-xs">
                {t("recipe.fat", "脂肪")}
              </Label>
              <div className="flex items-center gap-1">
                <Input
                  id="fat"
                  type="number"
                  min={0}
                  value={nutrition.fat || ""}
                  onChange={(e) => onNutritionChange({ ...nutrition, fat: parseInt(e.target.value) || undefined })}
                  placeholder="10"
                  className="h-8"
                />
                <span className="text-xs text-muted-foreground">g</span>
              </div>
            </div>
          </div>
        </CollapsibleContent>
      </Collapsible>
    </div>
  );
};

export default RecipeBasicStep;
