import { useTranslation } from "react-i18next";
import { Plus, Trash2, Image, X, Loader2, GripVertical } from "lucide-react";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { RecipeStep } from "./RecipeTypes";
import { useRef, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

const MAX_STEP_IMAGES = 3;

interface RecipeStepsStepProps {
  steps: RecipeStep[];
  onChange: (steps: RecipeStep[]) => void;
}

const RecipeStepsStep = ({ steps, onChange }: RecipeStepsStepProps) => {
  const { t } = useTranslation();
  const [uploadingIndex, setUploadingIndex] = useState<number | null>(null);
  const imageInputRefs = useRef<(HTMLInputElement | null)[]>([]);

  const getStepImages = (step: RecipeStep): string[] => {
    if (step.image_urls && step.image_urls.length > 0) return step.image_urls;
    if (step.image_url) return [step.image_url];
    return [];
  };

  const addStep = () => {
    const newOrder = steps.length + 1;
    onChange([...steps, { order: newOrder, description: "", image_urls: [] }]);
  };

  const updateStep = (index: number, field: keyof RecipeStep, value: any) => {
    const updated = [...steps];
    updated[index] = { ...updated[index], [field]: value };
    onChange(updated);
  };

  const removeStep = (index: number) => {
    const updated = steps
      .filter((_, i) => i !== index)
      .map((step, i) => ({ ...step, order: i + 1 }));
    onChange(updated);
  };

  const removeImage = (stepIndex: number, imageIndex: number) => {
    const images = getStepImages(steps[stepIndex]);
    const newImages = images.filter((_, i) => i !== imageIndex);
    updateStep(stepIndex, "image_urls", newImages);
    // Clear legacy field
    updateStep(stepIndex, "image_url", undefined);
  };

  const handleImageUpload = async (index: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const currentImages = getStepImages(steps[index]);
    if (currentImages.length >= MAX_STEP_IMAGES) {
      toast.error(t("recipe.maxStepImages", "每个步骤最多上传{{max}}张图片", { max: MAX_STEP_IMAGES }));
      return;
    }

    if (file.size > 5 * 1024 * 1024) {
      toast.error(t("common.imageTooLarge", "图片不能超过5MB"));
      return;
    }

    setUploadingIndex(index);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");

      const fileExt = file.name.split(".").pop();
      const fileName = `${user.id}/${Date.now()}-step-${index}.${fileExt}`;

      const { error: uploadError } = await supabase.storage
        .from("community-posts")
        .upload(fileName, file);

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from("community-posts")
        .getPublicUrl(fileName);

      const newImages = [...currentImages, publicUrl];
      const updated = [...steps];
      updated[index] = { ...updated[index], image_urls: newImages, image_url: undefined };
      onChange(updated);
    } catch (error) {
      console.error("Upload error:", error);
      toast.error(t("common.uploadError", "上传失败"));
    } finally {
      setUploadingIndex(null);
      if (imageInputRefs.current[index]) {
        imageInputRefs.current[index]!.value = "";
      }
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <Label className="text-base font-medium">{t("recipe.steps", "烹饪步骤")} *</Label>
        <span className="text-sm text-muted-foreground">
          {steps.filter(s => s.description).length} {t("recipe.stepsCount", "步")}
        </span>
      </div>

      <div className="space-y-4">
        {steps.map((step, index) => {
          const images = getStepImages(step);
          return (
            <div key={index} className="p-4 border rounded-lg space-y-3 bg-card">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <GripVertical className="h-4 w-4 text-muted-foreground" />
                  <span className="font-medium text-primary">
                    {t("recipe.stepNumber", "第{{n}}步", { n: index + 1 })}
                  </span>
                </div>
                <Button
                  type="button"
                  variant="ghost"
                  size="icon"
                  onClick={() => removeStep(index)}
                  disabled={steps.length === 1}
                >
                  <Trash2 className="h-4 w-4 text-destructive" />
                </Button>
              </div>

              <Textarea
                value={step.description}
                onChange={(e) => updateStep(index, "description", e.target.value)}
                placeholder={t("recipe.stepDescriptionPlaceholder", "描述这一步的操作...")}
                className="min-h-[80px]"
              />

              {/* Step Images */}
              <div>
                <input
                  ref={(el) => (imageInputRefs.current[index] = el)}
                  type="file"
                  accept="image/*"
                  className="hidden"
                  onChange={(e) => handleImageUpload(index, e)}
                />
                
                {images.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-2">
                    {images.map((url, imgIdx) => (
                      <div key={imgIdx} className="relative w-24 h-20 rounded-lg overflow-hidden bg-muted">
                        <img src={url} alt="" className="w-full h-full object-cover" />
                        <button
                          type="button"
                          onClick={() => removeImage(index, imgIdx)}
                          className="absolute top-1 right-1 p-1 bg-black/50 rounded-full text-white hover:bg-black/70"
                        >
                          <X className="h-3 w-3" />
                        </button>
                      </div>
                    ))}
                  </div>
                )}

                {images.length < MAX_STEP_IMAGES && (
                  <button
                    type="button"
                    onClick={() => imageInputRefs.current[index]?.click()}
                    disabled={uploadingIndex === index}
                    className="flex items-center gap-2 text-sm text-muted-foreground hover:text-primary transition-colors"
                  >
                    {uploadingIndex === index ? (
                      <Loader2 className="h-4 w-4 animate-spin" />
                    ) : (
                      <Image className="h-4 w-4" />
                    )}
                    <span>
                      {images.length === 0
                        ? t("recipe.addStepImage", "添加步骤图片（可选）")
                        : t("recipe.addMoreImages", "继续添加 ({{current}}/{{max}})", { current: images.length, max: MAX_STEP_IMAGES })}
                    </span>
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>

      <Button
        type="button"
        variant="outline"
        onClick={addStep}
        className="w-full"
      >
        <Plus className="h-4 w-4 mr-2" />
        {t("recipe.addStep", "添加步骤")}
      </Button>
    </div>
  );
};

export default RecipeStepsStep;
